import{_ as c,a as o,b as a,c as n,d as y}from"./TestNavigationButtons-36aaba3d.js";import{_ as u}from"./QuestionTemp4.vue_vue_type_script_setup_true_lang-4a589825.js";import{S as s}from"./SeihoTestLayout-4ba09b5d.js";import{o as v,c as i,w as r,b as p,a as e}from"./app-0fc1b258.js";import"./AdSenseUnit.vue_vue_type_script_setup_true_lang-2ec5dd9e.js";const b={class:"bg-gray-100 text-gray-800 py-10"},k={class:"max-w-4xl mx-auto mt-4 space-y-2"},t="生命保険計理",l="2020年度 フォームA",P={__name:"Keiri2020a",setup(m){return(f,x)=>(v(),i(s,{title:t},{default:r(()=>[p("section",b,[e(c,{title:t,description:l}),p("div",k,[e(u,{questionNumber:1,title:t,subject:l,contents:[{answer:"0.99247",questionTitle:"生存率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"生存率とは、「ある年齢の人が、次の年齢まで生き残る割合」のこと。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["生存率 = 期末の生存数 ÷ 期初の生存数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["生存率（45歳 → 50歳）","= 50歳の生存数 ÷ 45歳の生存数","= 97,539 ÷ 98,279 = 0.992469…"]},{type:"result",value:"▶ 答え 0.99247（小数第6位を四捨五入）"}]},{answer:"98,501",questionTitle:"生存数",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"「5年後に何人残るか」は、今の人数に5年間生き残る割合（生存率）を掛けることで求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formula",value:"N年後の生存者数 = 基準年齢の人数 × 生存率"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"5年後の生存者数"},{type:"formulaBlock",value:["基準年齢（55歳）の人数 × 生存率（55歳 → 60歳）","= 100,000 × 94,995 ÷ 96,441 = 98,500.6…"]},{type:"result",value:"▶ 答え 98,501（小数第1位を四捨五入）"}]},{answer:"1.12",questionTitle:"平均余命",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"平均余命とは、その年齢の全員がこれから生きる年数を全部足して、今の人数で割ったもの。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["延べ生存年数 = 死亡数 × 平均生存年数","平均余命 = 延べ生存年数の合計 ÷ 生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 各年齢の延べ生存年数"},{type:"note",value:"各年齢の死亡者は、その年齢内で平均<strong>0.5年</strong>生存したとみなして計算する。"},{type:"formulaBlock",value:["108歳：58.951 × 0.5 = 29.4755 → 29.48","109歳：25.888 × 1.5 = 38.832 → 38.83","110歳：10.1008 × 2.5 = 25.252 → 25.25","111歳：3.4515 × 3.5 = 12.08025 → 12.08","112歳：1.0162 × 4.5 = 4.5729 → 4.57","113歳：0.3155 × 5.5 = 1.73525 → 1.74"]},{type:"text",value:"② 108歳～113歳の延べ生存年数の合計"},{type:"note",value:"108歳以上の全員が、合計で何年分生きたかを合算する。"},{type:"formulaBlock",value:["29.48 + 38.83 + 25.25 + 12.08 + 4.57 + 1.74 = 111.95"]},{type:"text",value:"③ 108歳の平均余命"},{type:"formulaBlock",value:["108歳～113歳の延べ生存年数の合計 ÷ 108歳の生存者数","= 111.95 ÷ 99.723","= 1.12226…"]},{type:"result",value:"▶ 答え 1.12（小数第3位を四捨五入）"}]},{answer:"955,236",questionTitle:"保険金総額の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"1年定期保険では、1年間に死亡した人に保険金を支払う。したがって、まず死亡者全員に支払う保険金の合計額を出し、支払い時点を年央（期央）とみなして、期央払現価率で割り引いて現価を求める。"},{type:"note",value:"※期央払現価率とは、年の真ん中で支払われると仮定したときの割引係数。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["合計保険金額 = 保険金 × 死亡数","現価 = 合計保険金額 × 期央払現価率（利率1.0%）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 合計保険金額"},{type:"formulaBlock",value:["保険金（500万円） × 死亡数（50歳）","= 5,000千円 × 192人","= 960,000千円"]},{type:"text",value:"② 現価（年央払）"},{type:"formulaBlock",value:["合計保険金額 × 期央払現価率（利率1.0%）","= 960,000千円 × 0.995037","= 955,235.52千円"]},{type:"result",value:"▶ 答え：955,236千円（千円未満四捨五入）"}]},{answer:"9,790",questionTitle:"純保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"純保険料は、必要な保険金総額の現価を、加入者全員で負担する額。したがって、必要な現価を年始生存者数で割る。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["純保険料 = 必要な現価 ÷ 年始生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["純保険料","= 必要な現価（問４の解） ÷ 50歳の年始生存者数","= 955,236千円 ÷ 97,539人","= 9,790.1…円"]},{type:"result",value:"▶ 答え 9,790円（10円未満四捨五入）"}]}],labels:["ア","キ","ウ","コ","カ"]}),e(u,{questionNumber:6,title:t,subject:l,contents:[{answer:"2,348",questionTitle:"複利計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"複利では、元金に利息が組み込まれながら増えていく。まず6か月後の元利合計を求め、そこから元金を差し引いて利息を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 利率)<sup>運用期間</sup>","利息 = 元利合計 − 元金"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：300,000円","月利：0.13％ = 0.0013","運用期間：6か月"]},{type:"text",value:"① 元利合計"},{type:"formulaBlock",value:["= 300,000円 × (1 + 0.0013)<sup>6</sup>","= 300,000円 × 1.007826","= 302,347.8円"]},{type:"text",value:"② 利息"},{type:"formulaBlock",value:["= 302,347.8円 − 300,000円","= 2,347.8円"]},{type:"result",value:"▶ 答え 2,348円（円未満四捨五入）"}]},{answer:"317,217",questionTitle:"複利計算（半年複利）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年利1.4％で半年複利の場合、半年ごとに0.7％ずつ増える。4年間では半年が8回あるため、半年利率で8回複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 期間利率)<sup>複利回数</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：300,000円","年利：1.4％","半年利率：= 1.4％ ÷ 2 = 0.7％ = 0.007","複利回数：= 4年 × 年2回 = 8回"]},{type:"formulaBlock",value:["元利合計","= 300,000円 × (1 + 0.007)<sup>8</sup>","= 300,000円 × 1.057389","= 317,216.7円"]},{type:"result",value:"▶ 答え 317,217円（円未満四捨五入）"}]},{answer:"1.31",questionTitle:"実利率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"実利率とは、1年間に実際どれだけ増えるかを示す利率。名称利率が年率でも、年に複数回利息が付く場合は、その回数分だけ複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["実利率 =（ 1 + 名称利率 ÷ 転化回数）<sup>転化回数</sup> - 1"]},{type:"note",value:"転化回数：1年間に利息を元金に繰り入れる回数"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 1回あたりの利率"},{type:"formulaBlock",value:["= 0.013 ÷ 4","= 0.00325"]},{type:"text",value:"② 実利率"},{type:"formulaBlock",value:["= (1 + 0.00325)<sup>4</sup> − 1","= 1.013070 − 1","= 0.013070 = 1.3070％"]},{type:"result",value:"▶ 答え 1.31％（小数第3位を四捨五入）"}]},{answer:"1.83",questionTitle:"年平均利回り",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"まず、3年間の複利でどれだけ増えたか（総利回り）を求める。その後、それを3年で平均したものが年平均利回り。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["総利回り = (1 + 複利利率)<sup>期間</sup> − 1","年平均利回り = 総利回り ÷ 期間"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["複利利率：1.8％ = 0.018","投資期間：3年"]},{type:"text",value:"① 総利回り"},{type:"formulaBlock",value:["= (1 + 0.018)<sup>3</sup> − 1","= 1.05497 − 1","= 0.05497"]},{type:"text",value:"② 年平均利回り"},{type:"formulaBlock",value:["= 0.05497 ÷ 3","= 0.01832 = 1.832％"]},{type:"result",value:"▶ 答え 1.83％（小数第3位を四捨五入）"}]},{answer:"3,694,805",questionTitle:"現在必要資金の計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"将来400万円を得るために、今いくら必要かを求める問題。将来価値がわかっているので、複利を逆算（割り戻す）して現在価値を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["現在価値 = 将来価値 ÷ (1 + 利率)<sup>期間</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["将来価値：4,000,000円","年利率：1.6％ = 0.016","期間：5年"]},{type:"formulaBlock",value:["現在価値","= 4,000,000 ÷ (1 + 0.016)<sup>5</sup>","= 4,000,000 ÷ 1.082608","= 3,694,804.9…"]},{type:"result",value:"▶ 答え 3,694,805円（円未満四捨五入）"}]}],labels:["カ","ク","ア","ウ","ケ"]}),e(o,{questionNumber:3,title:t,subject:l,contents:["未経過保険料","危険準備金","4月1日から翌年3月31日","契約月","保険リスク"],labels:["キ","イ","エ","ケ","コ"]}),e(o,{questionNumber:4,title:t,subject:l,contents:["保証はない","変動保険金額","毎日","契約者","生命保険会社"],labels:["コ","カ","キ","ケ","イ"]}),e(u,{questionNumber:21,title:t,subject:l,contents:[{answer:"818,393千円",questionTitle:"死亡保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"保険期間（40〜42歳）の各年齢で死亡した場合、死亡保険金が支払われる。支払いは年央（期央）と仮定されるため、各年齢の「死亡保険金 × 死亡数」を期央払現価率で割り引き、現価を合計する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["各年齢の死亡保険金現価 = 死亡保険金 × 死亡数 × 期央払現価率","死亡保険金現価の合計 = 各年齢の死亡保険金現価の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["死亡保険金：300万円 = 3,000千円","保険期間：3年（40〜42歳）","支払い：年央（期央）と仮定"]},{type:"text",value:"① 各年齢の死亡保険金現価"},{type:"formulaBlock",value:["40歳：3,000千円 × 87 × 0.995037 = 259,705千円","41歳：3,000千円 × 92 × 0.985185 = 271,911千円","42歳：3,000千円 × 98 × 0.975431 = 286,777千円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["死亡保険金現価の合計","= 259,705 + 271,911 + 286,777","= 818,393千円"]},{type:"result",value:"▶ 答え 818,393千円"}]},{answer:"286,786,051千円",questionTitle:"満期保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"満期保険金は、保険期間満了時（3年後）に生存している人に支払われる。したがって、まず 3年後の生存者数 × 保険金額 で将来の支払総額を求め、それを 期末払現価率 で割り引いて現価を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["満期保険金の現価 = 5年後の生存者数 × 保険金額 × 期末払現価率（3年）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：300万円 = 3,000千円","3年後（43歳）の生存数：98,492人","3年の期末払現価率：0.970590"]},{type:"formulaBlock",value:["満期保険金の現価","= 98,492 × 3,000 × 0.970590","= 286,786,050.84千円"]},{type:"result",value:"▶ 答え 286,786,051千円（千円未満四捨五入）"}]},{answer:"7,407,600千円",questionTitle:"予定事業費の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"予定事業費が「保険金1000円につき25円」と与えられているので、まず 1人あたりの予定事業費を求める。その後、加入時（400歳）の生存者数を掛けて、全体の予定事業費（現価）を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["1人あたりの予定事業費 = 保険金額 ×（25 ÷ 1000）","予定事業費の現価（合計） = 1人あたりの予定事業費 × 加入時の生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：300万円 = 3,000千円","予定事業費：保険金1000円につき25円 = 25 ÷ 1000","40歳の生存数：98,768人"]},{type:"text",value:"① 1人あたりの予定事業費"},{type:"formulaBlock",value:["= 3,000千円 ×（25 ÷ 1000）","= 3,000 × 0.025","= 75千円"]},{type:"text",value:"② 予定事業費の現価（合計）"},{type:"formulaBlock",value:["= 75千円 × 98,768人","= 7,407,600千円"]},{type:"result",value:"▶ 答え 7,407,600千円（千円未満四捨五入）"}]},{answer:"1,006,460円",questionTitle:"養老保険の年払営業保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年払営業保険料 P は、収支相当の原則（収入現価 = 支出現価）で求める。"},{type:"text",value:"収入現価：各年齢で生存している人が払う保険料 P を期始払として現価に直して合計する。"},{type:"text",value:"支出現価：死亡保険金・満期保険金・予定事業費の現価を合計する（問21〜23の結果）。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["収支相当の原則：収入現価 = 支出現価","各年齢の収入現価（期始払） = 生存数 × P × 期始払現価率","支出現価 = 死亡保険金現価 + 満期保険金現価 + 予定事業費現価"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 収入現価（40〜42歳、期始払）"},{type:"formulaBlock",value:["40歳：P × 98,681 × 1.000000 = 98,681P","41歳：P × 98,565 × 0.990099 = 97,589P","42歳：P × 98,439 × 0.980296 = 96,518P"]},{type:"formulaBlock",value:["収入現価の合計","= 98,681P + 97,589P + 96,518P","= 292,788P"]},{type:"text",value:"② 支出現価（問21〜23より）"},{type:"formulaBlock",value:["死亡保険金の現価（問21）= 818,393千円","満期保険金の現価（問22）= 286,786,051千円","予定事業費の現価（問23）= 7,407,600千円"]},{type:"formulaBlock",value:["支出現価","= 818,393 + 286,786,051 + 7,407,600","= 295,012,044千円 = 295,012,044,000円"]},{type:"text",value:"③ 収支相当の原則より P を求める"},{type:"formulaBlock",value:["292,788P = 295,012,044,000円","P = 295,012,044,000 ÷ 292,788","P = 1,006,456…円"]},{type:"result",value:"▶ 答え 1,006,460円（10円未満四捨五入）"}]}],labels:["イ","ア","ウ","ア"]}),e(a,{questionNumber:25,title:t,subject:l,contents:["正しい","","正しい"]}),e(a,{questionNumber:26,title:t,subject:l,contents:["正しい","","正しい"]}),e(a,{questionNumber:27,title:t,subject:l,contents:["","正しい","正しい"]}),e(a,{questionNumber:28,title:t,subject:l,contents:["正しい","","正しい"]}),e(a,{questionNumber:29,title:t,subject:l,contents:["","正しい","正しい"]}),e(a,{questionNumber:30,title:t,subject:l,contents:["正しい","正しい",""]}),e(n,{questionNumber:31,title:t,subject:l,items:[{label:"解",content:""},{label:"解",content:"正しい"},{label:"解",content:""},{label:"解",content:"正しい"},{label:"解",content:""},{label:"解",content:""},{label:"解",content:""},{label:"解",content:"正しい"},{label:"解",content:""},{label:"解",content:"正しい"},{label:"オ",content:""},{label:"エ",content:"完全生命表"},{label:"オ",content:""},{label:"イ",content:"高くなる"},{label:"ア",content:"大数"},{label:"ウ",content:"貯蓄保険料"},{label:"ア",content:"危険保険金"},{label:"ア",content:"定款"},{label:"ア",content:"保険種類別"},{label:"ウ",content:"純保険料率"}]})]),e(y,{"previous-route":"keiri2021c","next-route":"keiri2020b"})])]),_:1}))}};export{P as default};
